const fileName = $('Google Drive Trigger').first().json.name;
const ext = fileName.split('.').pop().toLowerCase();
let rows = [];

if (ext === 'csv') {
  const csvText = Buffer.from($input.first().binary.data.data, 'base64').toString('utf8');
  const lines = csvText.split('\n').filter(l => l.trim());
  if (lines.length < 2) throw new Error('CSV vazio');
  const headers = lines[0].split(',').map(h => h.replace(/^"|"$/g, '').trim());
  rows = lines.slice(1).map(line => {
    const vals = line.match(/(?:"[^"]*"|[^,])+/g) || [];
    const obj = {};
    headers.forEach((h, i) => { obj[h] = (vals[i] || '').replace(/^"|"$/g, '').trim(); });
    return obj;
  });
} else {
  throw new Error('Formato não suportado diretamente — converta para CSV no Apollo');
}

const APOLLO_MAP = {
  empresa:   ['Account Name', 'Company'],
  email:     ['Email'],
  linkedin:  ['Person Linkedin Url', 'LinkedIn Url'],
  cidade:    ['City'],
  categoria: ['Title'],
  website:   ['Website'],
};
const cols = rows.length > 0 ? Object.keys(rows[0]) : [];
let matched = 0;
for (const apolloCols of Object.values(APOLLO_MAP)) {
  if (apolloCols.some(c => cols.includes(c))) matched++;
}
if (cols.includes('First Name') && cols.includes('Last Name')) matched++;
const confidence = cols.length > 0 ? matched / (Object.keys(APOLLO_MAP).length + 1) : 0;

return [{ json: { rows, fileName, confidence, columns: cols } }];

const { rows, fileName } = $input.first().json;
const leads = rows.map(row => ({
  empresa:          row['Account Name'] || row['Company'] || '',
  contato:          [row['First Name'], row['Last Name']].filter(Boolean).join(' ') || null,
  email:            row['Email'] || null,
  linkedin:         row['Person Linkedin Url'] || row['LinkedIn Url'] || null,
  cidade:           row['City'] || null,
  categoria:        row['Title'] || null,
  website:          row['Website'] || null,
  whatsapp:         null, telefone: null, bairro: null,
  cnpj:             null, instagram: null, resumo_analitico: null,
  warnings: {}, errors: {},
})).filter(l => l.empresa.trim().length > 0);
return [{ json: { leads, fileName } }];

