const fileName = $('Montar payload Apollo').first()?.json?.fileName
               || $('Fallback IA /map').first()?.json?.fileName
               || 'unknown.csv';

const rawContent = $input.first().json.choices[0].message.content;
let normalizedLeads;
try {
  normalizedLeads = JSON.parse(rawContent).leads;
} catch {
  throw new Error('OpenAI retornou JSON inválido: ' + rawContent.slice(0, 200));
}

return [{ json: {
  leads: normalizedLeads,
  fileName,
  metadata: { source: 'google_drive', filename: fileName },
  options: { defaultOrigem: 'apollo' }
} }];
